export default function ContactSocialView({ branch }: ContactSocialViewProps) {
  const t = useTranslations('modal');

  // Build social links dynamically from branch data
  const socialLinks: SocialLink[] = [];

  if (branch.socialLinks) {
    if (branch.socialLinks.instagram) {
      socialLinks.push({
        platform: 'Instagram',
        icon: InstagramIcon,
        url: branch.socialLinks.instagram,
        color: 'bg-gradient-to-br from-purple-600 via-pink-600 to-orange-500'
      });
    }
    
    if (branch.socialLinks.tiktok) {
      socialLinks.push({
        platform: 'TikTok',
        icon: TikTokIcon,
        url: branch.socialLinks.tiktok,
        color: 'bg-black'
      });
    }
    
    if (branch.socialLinks.facebook) {
      socialLinks.push({
        platform: 'Facebook',
        icon: FacebookIcon,
        url: branch.socialLinks.facebook,
        color: 'bg-blue-600'
      });
    }
    
    if (branch.socialLinks.whatsapp) {
      socialLinks.push({
        platform: 'WhatsApp',
        icon: WhatsAppIcon,
        url: branch.socialLinks.whatsapp,
        color: 'bg-green-500'
      });
    }

    if (branch.socialLinks.snapchat) {
      socialLinks.push({
        platform: 'Snapchat',
        icon: SnapchatIcon,
        url: branch.socialLinks.snapchat,
        color: 'bg-yellow-400'
      });
    }
  }

  const formatHours = (open: string, close: string): string => {
    return `${open} - ${close}`;
  };

  return (
    <div className="contact-social-view">
      <h2 className="text-2xl font-bold mb-6 text-gray-900">
        {t('contactInfo')}
      </h2>

      {/* Contact Information Section */}
      <div className="contact-section space-y-4 mb-8">
        {branch.phone && (
          <div className="flex items-center gap-3 p-4 bg-gray-50 rounded-lg hover:bg-gray-100 transition-colors duration-200">
            <Phone className="w-5 h-5 text-primary" />
            <a
              href={`tel:${branch.phone}`}
              className="text-gray-800 font-medium hover:text-primary transition-colors duration-200"
            >
              {branch.phone}
            </a>
          </div>
        )}

        {branch.hours && (
          <div className="flex items-center gap-3 p-4 bg-gray-50 rounded-lg">
            <Clock className="w-5 h-5 text-primary" />
            <p className="text-gray-800 font-medium">
              {formatHours(branch.hours.open, branch.hours.close)}
            </p>
          </div>
        )}

        {/* Google Maps Button */}
        {branch.googleMapsUrl && (
          <div className="flex items-center gap-3 p-4 bg-gray-50 rounded-lg hover:bg-gray-100 transition-colors duration-200">
            <MapPin className="w-5 h-5 text-primary" />
            <a
              href={branch.googleMapsUrl}
              target="_blank"
              rel="noopener noreferrer"
              className="text-gray-800 font-medium hover:text-primary transition-colors duration-200"
            >
              {t('viewOnGoogleMaps')}
            </a>
          </div>
        )}
      </div>

      {/* Social Media Section - Only render if there are social links */}
      {socialLinks.length > 0 && (
        <div className="social-section relative">
          {/* Decorative Background Pattern */}
          <div className="absolute inset-0 bg-gradient-to-br from-primary-50 via-purple-50 to-pink-50 rounded-xl opacity-50 -z-10" />
          <div className="absolute inset-0 bg-[radial-gradient(circle_at_30%_50%,rgba(120,119,198,0.1),transparent_50%)] -z-10" />
          
          <div className="relative p-6 rounded-xl">
            <h3 className="text-xl font-semibold mb-4 text-gray-900 text-center">
              {t('followUs')}
            </h3>
            
            {/* Social Media Grid */}
            <div className="social-grid grid grid-cols-5 gap-4 justify-items-center">
              {socialLinks.map((link) => {
                const Icon = link.icon;
                return (
                  <a
                    key={link.platform}
                    href={link.url}
                    target="_blank"
                    rel="noopener noreferrer"
                    className={`social-button ${link.color} w-12 h-12 rounded-full flex items-center justify-center text-white shadow-md hover:scale-110 transition-transform duration-200 hover:shadow-lg`}
                    aria-label={link.platform}
                    title={link.platform}
                  >
                    {typeof Icon === 'function' ? <Icon /> : <Icon className="w-6 h-6" />}
                  </a>
                );
              })}
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
